# --- Session Management Functions ---

sub _generate_session_id {
    my $id = join '', map { chr(int(rand(26)) + (rand > 0.5 ? 97 : 65)) } 1..32;
    $id .= time;
    return $id;
}

sub _get_session_file_path {
    my ($id) = @_;
    return "$SESSION_DIR/sess_$id";
}

sub _load_session {
    # Try to get session ID from cookie
    my %cookies = CGI::Cookie->fetch;
    $session_id = $cookies{$SESSION_COOKIE_NAME} ? $cookies{$SESSION_COOKIE_NAME}->value : undef;

    if ($session_id) {
        $session_file_path = _get_session_file_path($session_id);

        if (-e $session_file_path) {
            # Open and lock session file for reading
            if (open $session_fh, '<', $session_file_path) {
                flock $session_fh, LOCK_SH or die "Cannot get shared lock on $session_file_path: $!";
