                        close $session_fh; # Release lock
                        unlink $session_file_path; # Delete timed out session
                        $session_id = undef; # Force new session
                    } else {
                        # Session loaded successfully, update access time
                        $session_data->{_last_access} = time;
                    }
                }
            } else {
                warn "Could not open session file $session_file_path for reading: $!";
                $session_id = undef; # Force new session if file cannot be opened
            }
        } else {
