    };

    # Set new session cookie
    my $cookie = CGI::Cookie->new(
        -name    => $SESSION_COOKIE_NAME,
        -value   => $session_id,
        -expires => '+1M', # Expires in 1 month, or when browser closes, or based on application logic
        -path    => '/',
        -httponly => 1, # Mitigate XSS attacks
        -secure  => ($ENV{HTTPS} && $ENV{HTTPS} eq 'on' ? 1 : 0), # Only send over HTTPS if applicable
    );
    print $cookie->header, "\n";

    # Open and lock new session file for writing (will be created)
