sub _save_session {
    # If a session file was opened, ensure it's still open for writing
    # If not, it means a new session was created or an old one was invalid.
    # We must ensure the file handle is exclusive for writing the updated data.

    # Ensure the file handle is in exclusive write mode for saving.
    # If it was opened for reading initially, we need to reopen it for writing.
    # If it was opened for writing (new session), it's already EX.

    # Seek to beginning, truncate, and write
    unless (seek $session_fh, 0, 0) {
        die "Cannot seek to beginning of $session_file_path: $!";
    }
    unless (truncate $session_fh, 0) {
        die "Cannot truncate $session_file_path: $!";
    }

    # Upgrade lock if it was only shared
    flock $session_fh, LOCK_EX or die "Cannot upgrade lock on $session_file_path: $!";

    nstore($session_data, $session_fh);

    # Release the lock and close the file
    flock $session_fh, LOCK_UN or warn "Cannot release lock on $session_file_path: $!";
    close $session_fh or warn "Cannot close session file $session_file_path: $!";
