    print $cookie->header, "\n";

    # Close and delete session file
    if ($session_fh) {
        flock $session_fh, LOCK_UN or warn "Cannot release lock on $session_file_path before deleting: $!";
        close $session_fh or warn "Cannot close session file $session_file_path before deleting: $!";
    }
    if ($session_file_path && -e $session_file_path) {
